# --- Create Targets for Upstreams ---
def create_target(upstream_id, target_address, weight=100, tags=None):
    data = {
        "target": target_address,
        "weight": weight
    }
    if tags:
        data["tags"] = tags

    try:
        response = requests.post(f"{KONG_ADMIN_API_URL}/upstreams/{upstream_id}/targets", json=data)
        response.raise_for_status()
        print(f"Target '{target_address}' added to upstream '{upstream_id}' successfully: {response.json()['id']}")
        return response.json()
    except requests.exceptions.HTTPError as e:
        # Kong allows duplicate targets if they have different IDs (which they do on creation)
        # but also returns 409 if a target with the exact same target+weight exists and is active.
        # For idempotency, you might want to fetch targets first and check.
        if e.response.status_code == 409:
            print(f"Target '{target_address}' already exists in upstream '{upstream_id}'.")
            print(f"Response body: {e.response.text}")
        else:
            print(f"Error creating target '{target_address}' for upstream '{upstream_id}': {e}")
            print(f"Response body: {e.response.text}")
        return None
    except requests.exceptions.RequestException as e:
        print(f"Network or other error creating target '{target_address}' for upstream '{upstream_id}': {e}")
        return None

